// Get historical price data
const data = $input.item.json;

// Check if data exists
if (!data.values || data.values.length === 0) {
  return { json: { error: "No price data available", ticker: data.meta?.symbol } };
}

// Convert prices to numbers
const prices = data.values.map(v => parseFloat(v.close)).reverse();

// Function to calculate Fibonacci levels
function calculateFibonacciLevels() {
  // Find min and max prices
  const max = Math.max(...prices);
  const min = Math.min(...prices);
  const diff = max - min;

  return {
    level_0: min.toFixed(2),
    level_0_236: (min + diff * 0.236).toFixed(2),
    level_0_382: (min + diff * 0.382).toFixed(2),
    level_0_5: (min + diff * 0.5).toFixed(2),
    level_0_618: (min + diff * 0.618).toFixed(2),
    level_0_786: (min + diff * 0.786).toFixed(2),
    level_1: max.toFixed(2)
  };
}
// Function to identify support and resistance levels
function findSupportResistanceLevels() {
  // We need at least 30 data points
  if (prices.length < 30) {
    return { support: [], resistance: [] };
  }

  const supportLevels = [];
  const resistanceLevels = [];

  // Check each point (except edges) if it's a local minimum or maximum
  const lookback = 5; // how many points to check in each direction

  for (let i = lookback; i < prices.length - lookback; i++) {
    // Check for local minimum (support)
    let isMinimum = true;
    for (let j = i - lookback; j < i; j++) {
      if (prices[j] <= prices[i]) {
        isMinimum = false;
        break;
      }
    }

    for (let j = i + 1; j <= i + lookback; j++) {
      if (prices[j] <= prices[i]) {
        isMinimum = false;
        break;
      }
    }

    if (isMinimum) {
      supportLevels.push(prices[i]);
    }

    // Check for local maximum (resistance)
    let isMaximum = true;
    for (let j = i - lookback; j < i; j++) {
      if (prices[j] >= prices[i]) {
        isMaximum = false;
        break;
      }
    }

    for (let j = i + 1; j <= i + lookback; j++) {
      if (prices[j] >= prices[i]) {
        isMaximum = false;
        break;
      }
    }

    if (isMaximum) {
      resistanceLevels.push(prices[i]);
    }
  }

  // Sort and remove duplicates
  const uniqueSupports = [...new Set(supportLevels)];
  const uniqueResistances = [...new Set(resistanceLevels)];

  // Return only significant levels (up to 5 of each)
  return {
    support: uniqueSupports.sort((a, b) => b - a).slice(0, 5).map(p => p.toFixed(2)),
    resistance: uniqueResistances.sort((a, b) => a - b).slice(0, 5).map(p => p.toFixed(2))
  };
}

// Calculate levels
const fibonacciLevels = calculateFibonacciLevels();
const supportResistanceLevels = findSupportResistanceLevels();

// Return information with additional stock data
return {
  json: {
    ticker: data.meta.symbol,
    currentPrice: parseFloat(data.values[0].close).toFixed(2),
    fibonacci: fibonacciLevels,
    supportResistance: supportResistanceLevels,
    dataPoints: prices.length
  }
};

// Getting data from different sources
// Checking existence of objects before trying to access them
const items = $input.all();
const fibData = $input.first().json;

// Trying to locate bband and MACD data if they exist
let bbandsData = null;
let macdData = null;

// Trying to check if there is data in additional items
if (items.length > 1 && items[1] && items[1].json) {
  bbandsData = items[1].json;
}

if (items.length > 2 && items[2] && items[2].json) {
  macdData = items[2].json;
}

// Creating data structure for the response - ensure all fields exist
const result = {
  ticker: fibData.ticker || "לא ידוע",
  currentPrice: fibData.currentPrice || "0",
  timestamp: new Date().toISOString(),
  technicalAnalysis: {
    fibonacci: fibData.fibonacci || {},
    supportResistance: fibData.supportResistance || { support: [], resistance: [] },
    bollingerBands: {},
    macd: {}
  }
};

// Adding Bollinger Bands data - only if they exist
if (bbandsData && bbandsData.values && bbandsData.values.length > 0) {
  const bbands = bbandsData.values[0];
  result.technicalAnalysis.bollingerBands = {
    upperBand: parseFloat(bbands.upper_band).toFixed(2),
    middleBand: parseFloat(bbands.middle_band).toFixed(2),
    lowerBand: parseFloat(bbands.lower_band).toFixed(2)
  };
} else if (bbandsData && bbandsData.status === "ok") {
  // If returning another data format
  result.technicalAnalysis.bollingerBands = {
    upperBand: bbandsData.upperBand || bbandsData.upper_band || "0",
    middleBand: bbandsData.middleBand || bbandsData.middle_band || "0",
    lowerBand: bbandsData.lowerBand || bbandsData.lower_band || "0"
  };
}

// Adding MACD data - only if they exist
if (macdData && macdData.values && macdData.values.length > 0) {
  const macd = macdData.values[0];
  result.technicalAnalysis.macd = {
    macd: parseFloat(macd.macd).toFixed(2),
    signal: parseFloat(macd.signal).toFixed(2),
    histogram: parseFloat(macd.hist).toFixed(2)
  };
} else if (macdData && macdData.status === "ok") {
  // If returning another data format
  result.technicalAnalysis.macd = {
    macd: macdData.macd || "0",
    signal: macdData.signal || "0",
    histogram: macdData.histogram || macdData.hist || "0"
  };
}

// Creating summary and recommendation
let bullishFactors = [];
let bearishFactors = [];

// Analyzing Bollinger Bands - only if data exists
const bbands = result.technicalAnalysis.bollingerBands;
if (bbands.upperBand && bbands.lowerBand) {
  const currentPrice = parseFloat(result.currentPrice);
  const upperBand = parseFloat(bbands.upperBand);
  const lowerBand = parseFloat(bbands.lowerBand);

  if (!isNaN(currentPrice) && !isNaN(upperBand) && !isNaN(lowerBand)) {
    if (currentPrice > upperBand) {
      bearishFactors.push("מחיר מעל רצועת בולינגר העליונה - אפשרות לקנייה יתר");
    } else if (currentPrice < lowerBand) {
      bullishFactors.push("מחיר מתחת לרצועת בולינגר התחתונה - אפשרות למכירה יתר");
    }
  }
}

// Analyzing MACD - only if data exists
const macdInfo = result.technicalAnalysis.macd;
if (macdInfo.macd && macdInfo.signal) {
  const macd = parseFloat(macdInfo.macd);
  const signal = parseFloat(macdInfo.signal);

  if (!isNaN(macd) && !isNaN(signal)) {
    if (macd > signal) {
      bullishFactors.push("MACD מעל קו האיתות - אינדיקציה חיובית");
    } else {
      bearishFactors.push("MACD מתחת לקו האיתות - אינדיקציה שלילית");
    }
  }
}

// Analyzing support and resistance levels - only if data exists
const supportResistance = result.technicalAnalysis.supportResistance;
if (supportResistance.support && supportResistance.resistance) {
  const currentPrice = parseFloat(result.currentPrice);

  if (!isNaN(currentPrice)) {
    const supports = supportResistance.support.map(s => parseFloat(s)).filter(s => !isNaN(s));
    const resistances = supportResistance.resistance.map(r => parseFloat(r)).filter(r => !isNaN(r));

    // Finding the closest support level
    let closestSupport = null;
    let minSupportDist = Infinity;
    for (const support of supports) {
      if (support < currentPrice) {
        const dist = currentPrice - support;
        if (dist < minSupportDist) {
          minSupportDist = dist;
          closestSupport = support;
        }
      }
    }

    // Finding the closest resistance level
    let closestResistance = null;
    let minResistanceDist = Infinity;
    for (const resistance of resistances) {
      if (resistance > currentPrice) {
        const dist = resistance - currentPrice;
        if (dist < minResistanceDist) {
          minResistanceDist = dist;
          closestResistance = resistance;
        }
      }
    }

    // Adding support/resistance analysis
    if (closestSupport !== null) {
      const supportPercentage = ((currentPrice - closestSupport) / currentPrice * 100).toFixed(2);
      if (supportPercentage < 5) {
        bullishFactors.push(`המחיר קרוב לרמת תמיכה (${supportPercentage}%) - אפשרות להיפוך כלפי מעלה`);
      }
    }

    if (closestResistance !== null) {
      const resistancePercentage = ((closestResistance - currentPrice) / currentPrice * 100).toFixed(2);
      if (resistancePercentage < 5) {
        bearishFactors.push(`המחיר קרוב לרמת התנגדות (${resistancePercentage}%) - אפשרות להיפוך כלפי מטה`);
      }
    }
  }
}

// Analyzing Fibonacci - only if data exists
const fibonacci = result.technicalAnalysis.fibonacci;
if (fibonacci && Object.keys(fibonacci).length > 0) {
  const currentPrice = parseFloat(result.currentPrice);

  if (!isNaN(currentPrice)) {
    const fibLevels = Object.values(fibonacci).map(level => parseFloat(level)).filter(level => !isNaN(level));
    fibLevels.sort((a, b) => a - b);

    // Checking which Fibonacci level the price is at
    for (let i = 0; i < fibLevels.length - 1; i++) {
      if (currentPrice >= fibLevels[i] && currentPrice <= fibLevels[i+1]) {
        // If the price is close to a Fibonacci resistance level
        if (Math.abs(currentPrice - fibLevels[i+1]) / currentPrice * 100 < 2) {
          bearishFactors.push(`המחיר קרוב לרמת פיבונאצ'י ${[0, 23.6, 38.2, 50, 61.8, 78.6, 100][Math.min(i+1, 6)]}% - אפשרות להתנגדות`);
        }
        // If the price is close to a Fibonacci support level
        if (Math.abs(currentPrice - fibLevels[i]) / currentPrice * 100 < 2) {
          bullishFactors.push(`המחיר קרוב לרמת פיבונאצ'י ${[0, 23.6, 38.2, 50, 61.8, 78.6, 100][Math.min(i, 6)]}% - אפשרות לתמיכה`);
        }
        break;
      }
    }
  }
}

// Adding general recommendation based on factors
let recommendation = "";
if (bullishFactors.length > bearishFactors.length) {
  recommendation = "חיובית";
} else if (bearishFactors.length > bullishFactors.length) {
  recommendation = "שלילית";
} else {
  recommendation = "נייטרלית";
}

// Adding summary to the result
result.summary = {
  recommendation: recommendation,
  bullishFactors: bullishFactors,
  bearishFactors: bearishFactors
};

return { json: result };

// Replaces the former GPT-4o image-analysis step.
// Pulls the numeric RSI from the 'Get RSI' node and produces a small
// quantitative summary in the same shape the old vision node returned,
// so the downstream 'Set Variable' reference keeps working unchanged.
let rsi = null;
try {
  const r = $('Get RSI').first().json;
  const v = (r && r.values && r.values[0] && r.values[0].rsi) ? r.values[0].rsi : null;
  rsi = v !== null ? parseFloat(v) : null;
} catch (e) { rsi = null; }

let rsiState = "neutral";
if (rsi !== null) {
  if (rsi >= 70) rsiState = "overbought";
  else if (rsi <= 30) rsiState = "oversold";
}
const summary = {
  rsiNumeric: rsi,
  rsiState: rsiState,
  source: "twelvedata-rsi",
  note: "Quantitative indicators (RSI/MACD/Bollinger) drive this analysis; chart image is attached separately."
};
return [{ json: { choices: [ { message: { content: JSON.stringify(summary) } } ] } }];

/**
 * Custom code for n8n Code node to analyze news data from Alpha Vantage
 * 
 * - The code receives API data from the previous node
 * - Analyzes sentiment, leading articles, and hot topics
 * - Returns a structured JSON object for further processing
 */

const stockSymbol = $('Set Variables').first().json.stockSymbol
const allNews = $input.first().json.feed
  ;
const today = new Date().toISOString().split('T')[0]; // Current date in YYYY-MM-DD format

// Filter articles relevant to the stock
const relevantArticles = allNews.filter(article => {
  return article.ticker_sentiment && article.ticker_sentiment.some(ticker => 
    ticker.ticker === stockSymbol
  );
});

// Sentiment analysis
let sentimentCounts = {
  "Bullish": 0,
  "Somewhat-Bullish": 0,
  "Neutral": 0,
  "Somewhat-Bearish": 0,
  "Bearish": 0
};

let totalSentimentScore = 0;
let totalRelevanceScore = 0;

relevantArticles.forEach(article => {
  const stockTicker = article.ticker_sentiment.find(ticker => ticker.ticker === stockSymbol);
  if (stockTicker) {
    sentimentCounts[stockTicker.ticker_sentiment_label]++;
    totalSentimentScore += parseFloat(stockTicker.ticker_sentiment_score) * parseFloat(stockTicker.relevance_score);
    totalRelevanceScore += parseFloat(stockTicker.relevance_score);
  }
});

const avgSentimentScore = totalRelevanceScore > 0 ? totalSentimentScore / totalRelevanceScore : 0;

// Determining overall sentiment
let overallSentiment;
if (avgSentimentScore >= 0.35) {
  overallSentiment = "חיובי מאוד";
} else if (avgSentimentScore >= 0.15) {
  overallSentiment = "חיובי";
} else if (avgSentimentScore > -0.15) {
  overallSentiment = "נייטרלי";
} else if (avgSentimentScore > -0.35) {
  overallSentiment = "שלילי";
} else {
  overallSentiment = "שלילי מאוד";
}

// Most influential articles
const topArticles = relevantArticles
  .map(article => {
    const stockTicker = article.ticker_sentiment.find(ticker => ticker.ticker === stockSymbol);
    return {
      title: article.title,
      url: article.url,
      source: article.source,
      date: formatDate(article.time_published),
      sentiment_label: stockTicker ? stockTicker.ticker_sentiment_label : "N/A",
      sentiment_score: stockTicker ? parseFloat(stockTicker.ticker_sentiment_score) : 0,
      relevance_score: stockTicker ? parseFloat(stockTicker.relevance_score) : 0,
      impact_score: stockTicker ? Math.abs(parseFloat(stockTicker.ticker_sentiment_score) * parseFloat(stockTicker.relevance_score)) : 0
    };
  })
  .sort((a, b) => b.impact_score - a.impact_score)
  .slice(0, 5);

// Analysis of main topics
const topicsMap = {};

relevantArticles.forEach(article => {
  if (article.topics) {
    article.topics.forEach(topic => {
      if (!topicsMap[topic.topic]) {
        topicsMap[topic.topic] = {
          count: 0,
          relevance: 0
        };
      }
      topicsMap[topic.topic].count++;
      topicsMap[topic.topic].relevance += parseFloat(topic.relevance_score);
    });
  }
});

const hotTopics = Object.entries(topicsMap)
  .map(([topic, data]) => ({
    topic,
    article_count: data.count,
    average_relevance: (data.relevance / data.count).toFixed(2)
  }))
  .sort((a, b) => b.article_count - a.article_count)
  .slice(0, 5);

// Creating result object
const analysisResult = {
  stock_symbol: stockSymbol,
  analysis_date: today,
  sentiment_analysis: {
    overall_sentiment: overallSentiment,
    sentiment_score: parseFloat(avgSentimentScore.toFixed(4)),
    sentiment_distribution: sentimentCounts
  },
  top_articles: topArticles.map(article => ({
    title: article.title,
    source: article.source,
    url: article.url,
    date: article.date,
    sentiment: article.sentiment_label,
    impact_score: article.impact_score.toFixed(4)
  })),
  hot_topics: hotTopics,
  recent_trends: {
    description: getTrendDescription(overallSentiment, hotTopics),
    market_outlook: getMarketOutlook(overallSentiment)
  }
};

// Helper functions
function formatDate(dateStr) {
  if (!dateStr) return "N/A";

  try {
    // Format: 20250418T152049 -> 2025-04-18
    const year = dateStr.substring(0, 4);
    const month = dateStr.substring(4, 6);
    const day = dateStr.substring(6, 8);
    return `${year}-${month}-${day}`;
  } catch (e) {
    return dateStr;
  }
}

function getTrendDescription(sentiment, topics) {
  let description = "";

  if (sentiment === "חיובי מאוד" || sentiment === "חיובי") {
    description = "מגמה חיובית כאשר משקיעים מתמקדים בעיקר ב";
  } else if (sentiment === "שלילי מאוד" || sentiment === "שלילי") {
    description = "מגמה שלילית כאשר החששות העיקריים מתמקדים ב";
  } else {
    description = "מגמה מעורבת עם התמקדות ב";
  }

  if (topics.length > 0) {
    const topThreeTopics = topics.slice(0, Math.min(3, topics.length));
    description += topThreeTopics.map(t => t.topic).join(", ");
  } else {
    description += "מגוון נושאים";
  }

  return description + ".";
}

function getMarketOutlook(sentiment) {
  if (sentiment === "חיובי מאוד") {
    return "תחזית שוק חיובית מאוד. הסנטימנט הכללי מצביע על אמון משקיעים גבוה ופוטנציאל לעלייה בטווח הקצר.";
  } else if (sentiment === "חיובי") {
    return "תחזית שוק חיובית. ישנן אינדיקציות לאופטימיות זהירה בקרב משקיעים.";
  } else if (sentiment === "נייטרלי") {
    return "תחזית שוק מעורבת. קיימים כוחות מאזנים של אופטימיות ופסימיות בשוק.";
  } else if (sentiment === "שלילי") {
    return "תחזית שוק שלילית. ישנן דאגות בקרב משקיעים שעשויות להשפיע על המניה בטווח הקצר.";
  } else {
    return "תחזית שוק שלילית מאוד. קיימת אווירת זהירות משמעותית ונטייה למכירות.";
  }
}

// Return the object for further flow in n8n
return {
  json: analysisResult
};

// Function to generate yesterday's date in the required format
function getYesterdayDateFormat() {
  // Create a current date object
  const today = new Date();

  // Set the date to the previous day (yesterday)
  today.setDate(today.getDate() - 1);

  // Reset hours, minutes, seconds and milliseconds to 00:00:00.000
  today.setHours(0, 0, 0, 0);

  // Extract components
  const year = today.getFullYear();
  const month = String(today.getMonth() + 1).padStart(2, '0'); // Months in JS start from 0
  const day = String(today.getDate()).padStart(2, '0');
  const hours = String(today.getHours()).padStart(2, '0');
  const minutes = String(today.getMinutes()).padStart(2, '0');

  // Build the string in the required format
  return `${year}${month}${day}T${hours}${minutes}`;
}
// Calculate the date
const yesterdayDate = getYesterdayDateFormat();
// Return the result in the format required by n8n - array of objects
return [
  {
    json: {
      wanted_date: yesterdayDate
    }
  }
];

// Extract recent filing titles + dates from the SEC atom XML (text).
const xml = $input.first().json.data || "";
const entries = [];
const re = /<entry>([\s\S]*?)<\/entry>/g;
let m;
while ((m = re.exec(xml)) !== null && entries.length < 8) {
  const block = m[1];
  const t = (block.match(/<title>([\s\S]*?)<\/title>/) || [,""])[1].trim();
  const d = (block.match(/<updated>([\s\S]*?)<\/updated>/) || [,""])[1].trim();
  if (t) entries.push({ title: t, date: d });
}
return [{ json: { earningsFilings: entries } }];

const inp = $input.first().json;
let raw =
  (inp.message && inp.message.content) ??
  inp.output ??
  inp.content ??
  inp.text ??
  "";

let o = {};
if (typeof raw === "object" && raw !== null) {
  o = raw;
} else {
  let s = String(raw).trim();
  s = s.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/```$/i, "").trim();
  try {
    o = JSON.parse(s);
  } catch (e) {
    const start = s.indexOf("{");
    const end = s.lastIndexOf("}");
    if (start !== -1 && end !== -1 && end > start) {
      try { o = JSON.parse(s.slice(start, end + 1)); } catch (e2) { o = {}; }
    } else {
      o = {};
    }
  }
}

// Force the real ticker in everywhere the model left a placeholder "X"
const sym = o.stockSymbol || String($input.first().json.ticker || "").toUpperCase();
if (sym) {
  const fixX = (txt) => String(txt)
    .replace(/הנכס\s+X/g, "מניית " + sym)
    .replace(/נכס\s+X/g, "מניית " + sym)
    .replace(/מניית\s+X/g, "מניית " + sym)
    .replace(/מניה\s+X/g, "מניית " + sym);
  if (typeof o.technicalAnalysis === "string") o.technicalAnalysis = fixX(o.technicalAnalysis);
  if (typeof o.recommendationText === "string") o.recommendationText = fixX(o.recommendationText);
}

const lines = [];
if (o.stockSymbol)      lines.push("📊 *" + o.stockSymbol + "*");
if (o.Recommendation)   lines.push("🔔 " + o.Recommendation);
if (o.overallSentiment) lines.push("סנטימנט כללי: " + o.overallSentiment);
lines.push("");
if (o.recommendationText) {
  lines.push(String(o.recommendationText));
  lines.push("");
}

if (o.technicalAnalysis) {
  let ta = o.technicalAnalysis;
  let taText = "";
  if (typeof ta === "string") {
    taText = ta;
  } else if (typeof ta === "object") {
    if (ta.description) {
      taText += ta.description + "\n";
    }
    const inds = ta.keyIndicators || ta.indicators;
    if (Array.isArray(inds)) {
      for (const k of inds) {
        const name = k.name || "";
        const val = (k.currentValue !== undefined ? k.currentValue : (k.value !== undefined ? k.value : ""));
        const desc = k.description || k.signal || "";
        taText += "• " + name + (val !== "" ? " (" + val + ")" : "") + (desc ? ": " + desc : "") + "\n";
      }
    }
    if (!taText.trim()) {
      taText = JSON.stringify(ta);
    }
  }
  lines.push("📈 *ניתוח טכני*");
  lines.push(taText.replace(/\\n/g, "\n").trim());
  lines.push("");
}

if (Array.isArray(o.topArticles) && o.topArticles.length) {
  lines.push("📰 *כתבות בולטות*");
  for (const a of o.topArticles.slice(0, 5)) {
    lines.push("• " + (a.title || "") + (a.source ? " (" + a.source + ")" : ""));
  }
}

let text = lines.join("\n").trim();
if (!text) {
  text = "לא הצלחתי לפענח את הניתוח.";
}
if (text.length > 3900) {
  text = text.slice(0, 3900) + "…";
}

return [{ json: { text } }];
